const dados = $items("HTTP Request4").map(item => item.json.data).flat();

// Verifica se há dados válidos
if (!dados || !Array.isArray(dados) || dados.length < 2) {
  return [
    { erro: "Dados insuficientes ou inválidos no node 'HTTP Request'" }
  ];
}

// Filtra apenas os itens que têm o campo "enviada em"
const mensagensComData = dados.filter(item => item["enviada em"]);

if (mensagensComData.length < 2) {
  return [
    { erro: "Menos de duas mensagens com data encontradas" }
  ];
}

// Ordena as mensagens pela data/hora mais recente
mensagensComData.sort((a, b) => {
  const dataA = new Date(a["enviada em"].split(" ")[0].split("-").reverse().join("-") + "T" + a["enviada em"].split(" ")[1]);
  const dataB = new Date(b["enviada em"].split(" ")[0].split("-").reverse().join("-") + "T" + b["enviada em"].split(" ")[1]);
  return dataB - dataA;
});

// Seleciona a penúltima mensagem após a ordenação
