// Formata a data para dd/mm/aaaa
const partesData = penultimaMensagem["enviada em"].split(" ")[0].split("-");
const dataFormatada = `${partesData[0]}/${partesData[1]}/${partesData[2]}`;

// Limpa os números de telefone removendo "@c.us"
const telefoneOrigem = penultimaMensagem.from
  ? penultimaMensagem.from.replace("@c.us", "")
  : null;

const telefoneDestino = penultimaMensagem.to
  ? penultimaMensagem.to.replace("@c.us", "")
  : null;

// Retorna os dados formatados
return [
  {
    data: dataFormatada,
    telefoneOrigem: telefoneOrigem,
    telefoneDestino: telefoneDestino,
