  if (typeof texto !== 'string') return texto;

  return texto
    .replace(/[\p{Emoji_Presentation}\p{Extended_Pictographic}]/gu, '')
    .replace(/\s{2,}/g, ' ') // normaliza espaços extras
    .trim();
}

