  json: {
    phone: String(leadData.phone || ''),
    name: String(leadData.name || ''),
    current_stage: String(leadData.conversation_stage || leadData.stage || 'INTRO'),
    last_interaction: new Date().toISOString(),
    total_messages: 1,
    updated_at: new Date().toISOString(),
    status: (leadData.conversation_stage || '') === 'DONE' ? 'qualified' : 'active'
  }
}];

// ============================================
// SAFE CODE NODE - NUNCA QUEBRA
// ============================================

let hasProfile = false;
let profile = null;
let contextSummary = "";
let agentInstructions = "";
let leadTemperature = "novo";

try {

  const webhook = $input.first().json;
  const body = webhook.body || {};
  const phone = body.phone || body.sender || null;
  const name = body.name || "Cliente";
  const messageContent = body.content || "";

  const supabaseItems = $items("Buscar Perfil Supabase") || [];

  const validProfiles = supabaseItems
    .map(item => item.json)
    .filter(row => row && Object.keys(row).length > 0 && row.phone);

  if (validProfiles.length > 0) {
    hasProfile = true;
    profile = validProfiles[0];

    contextSummary = `Cliente conhecido: ${profile.name || name}`;
    agentInstructions = `Cliente recorrente. Não reiniciar do zero.`;

    if (profile.last_interaction) {
      const hoursSince =
        (new Date() - new Date(profile.last_interaction)) / (1000 * 60 * 60);

      if (hoursSince < 24) leadTemperature = "quente";
      else if (hoursSince < 168) leadTemperature = "morno";
      else leadTemperature = "frio";
    }

  } else {

    profile = {
      phone: phone,
      name: name,
      current_stage: "INTRO",
      status: "active",
      source: "whatsapp",
      created_at: new Date().toISOString(),
      last_interaction: new Date().toISOString(),
      total_messages: 1
    };

    contextSummary = `Novo cliente (${name}).`;
    agentInstructions = `Primeira conversa. Iniciar qualificação padrão.`;
  }

  // 👇 RETORNO GARANTIDO
  return [
    {
      json: {
        has_profile: hasProfile,
        is_returning_customer: hasProfile,
        lead_temperature: leadTemperature,
        profile: profile,
        context_summary: contextSummary,
        agent_instructions: agentInstructions,
        phone: phone,
        name: name,
        message: messageContent,
        timestamp: new Date().toISOString()
      }
    }
  ];

} catch (error) {

  // 👇 RETORNO GARANTIDO MESMO EM ERRO
  return [
    {
      json: {
        error: true,
        error_message: error.message,
        has_profile: false,
        is_returning_customer: false,
        lead_temperature: "novo",
        profile: null,
        context_summary: "Erro ao processar perfil.",
        agent_instructions: "Fluxo padrão.",
        timestamp: new Date().toISOString()
      }
    }
  ];
}

