  client_name,
  client_phone,
  property_address: property_address || 'A definir'
}));

return [{
  json: {
    success: true,
    visit_id: visitId,
    datetime: datetime,
    client_name: client_name,
    message: `Visita agendada com sucesso para ${client_name} em ${datetime}`
  }
}];

// Sistema de Follow-up Automatizado
// Identifica leads que precisam de acompanhamento

const leads = $input.all();

const followUps = leads.filter(lead => {
  const temperatura = lead.json.lead_temperature || 'frio';
  const ultimaInteracao = lead.json.updated_at;

  if (!ultimaInteracao) return false;

  const horasDesdeUltimaInteracao = (Date.now() - new Date(ultimaInteracao).getTime()) / (1000 * 60 * 60);

  // Leads frios: 48h sem interação
  if (temperatura === 'frio' && horasDesdeUltimaInteracao >= 48) {
    lead.json.followup_reason = 'lead_frio_48h';
    lead.json.followup_message = 'Olá! Vi que você teve interesse em imóveis. Ainda está procurando? Tenho novidades!';
    return true;
  }

  // Leads mornos: 24h sem interação
  if (temperatura === 'morno' && horasDesdeUltimaInteracao >= 24) {
    lead.json.followup_reason = 'lead_morno_24h';
    lead.json.followup_message = 'Oi! Encontrei alguns imóveis que podem interessar você. Quer ver?';
    return true;
  }

  // Leads com visita agendada: lembrete 1h antes
  if (lead.json.proxima_visita) {
    const horaVisita = new Date(lead.json.proxima_visita).getTime();
    const umaHoraAntes = horaVisita - (60 * 60 * 1000);
    if (Date.now() >= umaHoraAntes && Date.now() < horaVisita) {
      lead.json.followup_reason = 'lembrete_visita';
      lead.json.followup_message = 'Olá! Sua visita está agendada para daqui a pouco. Confirmada?';
      return true;
    }
  }

  return false;
});

return { json: { followups: followUps.map(f => f.json), total: followUps.length } };

// Logging Estruturado para Auditabilidade
const evento = $input.first().json;

const log = {
  timestamp: new Date().toISOString(),
  level: evento.level || 'INFO',
  categoria: evento.categoria || 'ATENDIMENTO',
  lead_telefone: evento.lead_telefone || null,
  sessao_id: evento.sessao_id || null,
  acao: evento.acao || null,
  etapa: evento.etapa || null,
  score: evento.score || null,
  imovel_id: evento.imovel_id || null,
  visita_id: evento.visita_id || null,
  detalhes: evento.detalhes || {},
  duracao_ms: evento.duracao_ms || null
};

// Console log para n8n
console.log(JSON.stringify(log));

return { json: { logged: true, log } };

// Buscar Imóveis com Match
const perfil = $input.first().json;

// Query base
let sql = `
  SELECT 
    id, titulo, tipo, bairro, quartos, area_util, valor, features, status,
    fotos->0 as foto_principal
  FROM imoveis 
  WHERE status = 'disponivel'
`;

const params = [];
const conditions = [];

// Filtro por quartos
if (perfil.quartos_ideais) {
  conditions.push(`quartos >= ${perfil.quartos_ideais}`);
}

// Filtro por bairros
if (perfil.bairros_preferidos && perfil.bairros_preferidos.length > 0) {
  const bairrosStr = perfil.bairros_preferidos.map(b => `'${b}'`).join(',');
  conditions.push(`bairro IN (${bairrosStr})`);
}

// Filtro por valor
if (perfil.faixa_valor) {
  if (perfil.faixa_valor.min) {
    conditions.push(`valor >= ${perfil.faixa_valor.min}`);
  }
  if (perfil.faixa_valor.max) {
    conditions.push(`valor <= ${perfil.faixa_valor.max}`);
  }
}

if (conditions.length > 0) {
  sql += ' AND ' + conditions.join(' AND ');
}

sql += ' ORDER BY valor ASC LIMIT 5';

return { json: { sql, params } };

const error = $input.first().json;
const errorInfo = {
  timestamp: new Date().toISOString(),
  node: error.node || 'unknown',
  error_message: error.message || error.error || 'Erro desconhecido',
  telefone: error.telefone || null
};

let errorClass = 'UNKNOWN';
let shouldRetry = false;
let userMessage = 'Ocorreu um erro. Por favor, tente novamente.';
let escalateToHuman = false;

if (error.message && error.message.includes('rate limit')) {
  errorClass = 'RATE_LIMIT';
  shouldRetry = true;
} else if (error.message && error.message.includes('calendar')) {
  errorClass = 'CALENDAR_ERROR';
  userMessage = 'Tive dificuldade para acessar a agenda. Vou transferir para um corretor.';
  escalateToHuman = true;
}

console.log(JSON.stringify({ level: 'ERROR', ...errorInfo, error_class: errorClass }));

return {
  json: {
    success: false,
    error_class: errorClass,
    should_retry: shouldRetry,
    escalate_to_human: escalateToHuman,
    user_message: userMessage
  }
};

const perfil = $input.first().json.perfil_extrato || {};
const imoveis = $input.all().map(i => i.json);

function calcularScore(imovel, perfil) {
  let score = 0;
  let maxScore = 10;
  const reasons = [];

  if (perfil.quartos_ideais && imovel.quartos >= perfil.quartos_ideais) {
    score += 3;
    reasons.push(`✓ ${imovel.quartos} quartos`);
  }

  if (perfil.bairros_preferidos?.includes(imovel.bairro)) {
    score += 3;
    reasons.push(`✓ Bairro: ${imovel.bairro}`);
  }

  if (perfil.faixa_valor && imovel.valor >= (perfil.faixa_valor.min || 0) && imovel.valor <= (perfil.faixa_valor.max || Infinity)) {
    score += 2.5;
    reasons.push(`✓ Valor: R$ ${imovel.valor?.toLocaleString()}`);
  }

  if (perfil.features_desejadas && imovel.features) {
    const matches = perfil.features_desejadas.filter(f => imovel.features[f]);
    if (matches.length > 0) {
      score += 1.5;
      reasons.push(`✓ Features: ${matches.join(', ')}`);
    }
  }

  return { score: Math.round(score / maxScore * 100) / 100, reasons };
}

const resultados = imoveis.map(imovel => ({
  ...imovel,
  match_score: calcularScore(imovel, perfil).score,
  match_reasons: calcularScore(imovel, perfil).reasons
})).sort((a, b) => b.match_score - a.match_score);

return { json: { top_matches: resultados.slice(0, 5), best_score: resultados[0]?.match_score || 0 } };

const TELEFONE = $json.telefone || $input.first().json.telefone;
const REDIS_KEY = `lead:perfil:${TELEFONE}`;

// Verificar se deve usar cache
const useCache = true;
const ttl = 3600; // 1 hora

return {
  json: {
    cache_key: REDIS_KEY,
    telefone: TELEFONE,
    use_cache: useCache,
    ttl: ttl,
    action: 'get_or_set'
  }
};

const leads = $input.all();
const now = new Date();

const analytics = {
  timestamp: now.toISOString(),
  total_leads: leads.length,
  por_temperatura: {},
  por_etapa: {},
  score_medio: 0,
  aguardando_followup: 0
};

let totalScore = 0;

leads.forEach(lead => {
  const temp = lead.json.lead_temperature || 'novo';
  analytics.por_temperatura[temp] = (analytics.por_temperatura[temp] || 0) + 1;

  const etapa = lead.json.current_step || 'INTRO';
  analytics.por_etapa[etapa] = (analytics.por_etapa[etapa] || 0) + 1;

  totalScore += lead.json.score || 0;

  // Verificar followup
  const updatedAt = new Date(lead.json.updated_at);
  const hoursSinceUpdate = (now - updatedAt) / (1000 * 60 * 60);
  if (hoursSinceUpdate > 24) {
    analytics.aguardando_followup++;
  }
});

analytics.score_medio = leads.length > 0 ? Math.round(totalScore / leads.length * 10) / 10 : 0;

return { json: analytics };

const dados = $input.first().json;

if (!dados.lead_telefone || !dados.proponente_nome || !dados.valor_proposta) {
  return { json: { success: false, error: 'Dados obrigatórios: telefone, nome, valor' } };
}

const ano = new Date().getFullYear();
const mes = String(new Date().getMonth() + 1).padStart(2, '0');
const codigo = `PROP${ano}${mes}${String(Math.floor(Math.random() * 9999) + 1).padStart(4, '0')}`;

return {
  json: {
    success: true,
    action: 'create_proposal',
    codigo_proposta: codigo,
    proponente_nome: dados.proponente_nome,
    proponente_telefone: dados.lead_telefone,
    valor_proposta: dados.valor_proposta,
    imovel_endereco: dados.imovel_endereco || null,
    forma_pagamento: dados.forma_pagamento || 'financiamento',
    status: 'rascunho',
    message: `Proposta ${codigo} gerada com sucesso!`
  }
};

const dados = $input.first().json;

if (!dados.proposta_id && !dados.lead_telefone) {
  return { json: { success: false, error: 'Proposta ID ou Telefone obrigatório' } };
}

const ano = new Date().getFullYear();
const seq = String(Math.floor(Math.random() * 999999) + 1).padStart(6, '0');
const numero = `CTR${ano}${seq}`;

return {
  json: {
    success: true,
    action: 'create_contract',
    numero_contrato: numero,
    comprador_nome: dados.comprador_nome || dados.proponente_nome,
    valor_total: dados.valor_total || dados.valor_proposta || 0,
    status: 'em_elaboracao',
    message: `Contrato ${numero} criado com sucesso!`
  }
};

const telefone = $json.lead_telefone || $input.first().json.telefone;

return {
  json: {
    action: 'query_proposals',
    sql: `
      SELECT id, codigo_proposta, proponente_nome, valor_proposta, status, created_at
      FROM propostas
      WHERE lead_telefone = $1
      ORDER BY created_at DESC
      LIMIT 10
    `,
    params: [telefone]
  }
};

const dados = $input.first().json;
const codigo = dados.codigo_proposta;
const novoStatus = dados.novo_status;

const statusValidos = ['rascunho', 'enviada', 'em_analise', 'aceita', 'recusada', 'contraproposta', 'expirada', 'cancelada'];

if (!codigo || !novoStatus) {
  return { json: { success: false, error: 'Código e status obrigatórios' } };
}

if (!statusValidos.includes(novoStatus)) {
  return { json: { success: false, error: 'Status inválido' } };
}

return {
  json: {
    success: true,
    action: 'update_status',
    codigo_proposta: codigo,
    novo_status: novoStatus,
    message: `Proposta ${codigo} → ${novoStatus}`
  }
};

const telefone = $json.lead_telefone || $input.first().json.telefone;

return {
  json: {
    action: 'query_contracts',
    sql: `
      SELECT id, numero_contrato, comprador_nome, valor_total, status, data_assinatura
      FROM contratos
      WHERE lead_telefone = $1
      ORDER BY created_at DESC
      LIMIT 10
    `,
    params: [telefone]
  }
};

