// ==========================
// 1. PARSE SEGURO DO OUTPUT
// ==========================
let analise = {};
let parseOk = false;

if ($json.output) {
  const raw = String($json.output).trim();
  const jsonMatch = raw.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    try {
      analise = JSON.parse(jsonMatch[0]);
      parseOk = true;
    } catch (e) {
      parseOk = false;
    }
  }
}

if (!parseOk) {
  const telefone = $("Dados1").first().json.Telefone || null;
  return [{
    json: {
      telefone: telefone,
      conversation_stage: null,
      score_confianca: 0,
      perfil_completo: false,
      perfil_minimo_viavel: false,
      p1_respondida: false, p2_respondida: false, p3_respondida: false, p4_respondida: false,
      p5_respondida: false, p6_respondida: false, p7_respondida: false, p8_respondida: false,
      p1_tipo_finalidade: null, p2_quartos_suites: null, p3_garagem_tamanho: null,
      p4_localizacao: null, p5_faixa_valor: null, p6_perfil_familiar: null,
      p7_necessidades_especiais: null, p8_urgencia: null,
      qtd_quartos: null, budget_min: null, budget_max: null,
      tipo_imovel: null, interest: null, caracteristicas_desejadas: null,
      bairros_preferencia: [],
      parse_error: true,
      raw_output: String($json.output || '').substring(0, 200)
    }
  }];
}

// ==========================
// 2. TELEFONE
// ==========================
const telefone = $("Dados1").first().json.Telefone || null;

// ==========================
// 3. PERFIL + RESPONDIDAS
// ==========================
const perfil = analise.perfil_extraido || {};
const resp = analise.respondidas || {};

let bairros = [];
if (Array.isArray(perfil.bairros_preferencia)) {
  bairros = perfil.bairros_preferencia;
} else if (typeof perfil.bairros_preferencia === 'string' && perfil.bairros_preferencia.trim() !== '') {
  bairros = perfil.bairros_preferencia.split(',').map(function(b) { return b.trim(); });
}

// Extrair budget_min e budget_max do campo p5_faixa_valor se necessário
let budgetMin = perfil.budget_min || null;
let budgetMax = perfil.budget_max || null;
const faixaValor = perfil.p5_faixa_valor || null;

if (!budgetMin && !budgetMax && faixaValor && typeof faixaValor === 'number') {
  budgetMax = faixaValor;
}

// ==========================
// 4. PAYLOAD COMPLETO
// ==========================
return [{
  json: {
    telefone: telefone,
    conversation_stage: analise.proximo_estagio || null,
    score_confianca: analise.score_confianca || 0,
    perfil_completo: analise.perfil_completo || false,
    perfil_minimo_viavel: analise.perfil_minimo_viavel || false,

    // Status P1-P8
    p1_respondida: resp.p1_respondida || false,
    p2_respondida: resp.p2_respondida || false,
    p3_respondida: resp.p3_respondida || false,
    p4_respondida: resp.p4_respondida || false,
    p5_respondida: resp.p5_respondida || false,
    p6_respondida: resp.p6_respondida || false,
    p7_respondida: resp.p7_respondida || false,
    p8_respondida: resp.p8_respondida || false,

    // Observações P1-P8
    p1_tipo_finalidade: perfil.tipo_imovel_p1 || perfil.tipo_imovel || null,
    p2_quartos_suites: perfil.p2_quartos_suites || null,
    p3_garagem_tamanho: perfil.p3_garagem_tamanho || null,
    p4_localizacao: perfil.p4_localizacao || null,
    p5_faixa_valor: String(faixaValor || ''),
    p6_perfil_familiar: perfil.p6_perfil_familiar || null,
    p7_necessidades_especiais: perfil.p7_necessidades_especiais || null,
    p8_urgencia: perfil.urgencia || perfil.prazo_mudanca || null,

    // Campos estruturais
    qtd_quartos: perfil.qtd_quartos || null,
    budget_min: budgetMin,
    budget_max: budgetMax,
    tipo_imovel: perfil.tipo_imovel_p1 || perfil.tipo_imovel || null,
    interest: perfil.interest || null,
    caracteristicas_desejadas: perfil.caracteristicas_desejadas || null,
    bairros_preferencia: bairros,

    parse_error: false
  }
}];

const lead = $json;
if (lead.atendimento_ia === 'pause') { return [{ json: { current_step: 'PAUSED', conversation_stage: lead.conversation_stage || 'INTRO', paused: true } }]; }
let proximaEtapa = lead.conversation_stage || 'INTRO';
if ((lead.score_confianca || 0) >= 3 && proximaEtapa !== 'DONE') { proximaEtapa = 'MATCH_READY'; }
if (lead.suggested_property_id) { proximaEtapa = 'PROPERTY_SUGGESTED'; }
let scoreQualificacao = (lead.score_confianca || 0) / 5;
let scoreFinal = Math.round(scoreQualificacao * 10);
return [{ json: { current_step: proximaEtapa, conversation_stage: proximaEtapa, lead_score: scoreFinal, score_confianca: lead.score_confianca || 0, perfil_completo: lead.perfil_completo || false, suggested_property_id: lead.suggested_property_id || null, telefone: lead.phone || null, name: lead.name || null } }];
